mapper.nql:
GO ${step} STEPS from
"${entityId}" OVER ${es} BIDIRECT
YIELD dst(edge) as dst, src(edge) as src ,type(edge) as edgeName,rank(edge) AS rank;

GO ${step} STEPS from
"${entityId}" OVER ${es} BIDIRECT
YIELD dst(edge) as dst, src(edge) as src ,type(edge) as edgeName,properties(edge) as e;

GO ${step} STEPS from
"${entityId}" OVER ${es} REVERSELY
YIELD dst(edge) as dst, src(edge) as src ,type(edge) as edgeName,rank(edge) AS rank;

GO ${step} STEPS from
"${entityId}" OVER ${es}
YIELD dst(edge) as dst, src(edge) as src ,type(edge) as edgeName,rank(edge) AS rank;

MATCH (v)
WHERE 1 == 1
@if ( isNotEmpty( like.vertexName ) ) {
AND lower(properties(v).NAME) CONTAINS lower( $like.vertexName )
@}
RETURN properties(v).NAME as NAME ,id(v) as id,tags(v) as tagList ORDER BY NAME ASC ;

GET SUBGRAPH ${ex.stepNumber} STEPS FROM ${ex.vertexInfoVOList} ${ex.direction}
${ex.edgeNameList}
YIELD VERTICES AS nodes, EDGES AS relationships;
